"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
  onStepClick?: (step: number) => void
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepItemContextValue = {
  step: number
  state: "active" | "completed" | "inactive"
}

const StepItemContext = React.createContext<StepItemContextValue | null>(null)

function useStepItem() {
  const context = React.useContext(StepItemContext)

  if (!context) {
    throw new Error("useStepItem must be used within a <StepperItem />")
  }

  return context
}

function Stepper({
  activeStep = 0,
  orientation = "horizontal",
  onStepClick,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
  onStepClick?: (step: number) => void
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation, onStepClick }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex gap-4",
          orientation === "horizontal"
            ? "flex-row items-center"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()
  const state =
    activeStep === step
      ? "active"
      : activeStep > step
        ? "completed"
        : "inactive"

  return (
    <StepItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        className={cn(
          "group/step-item flex items-center gap-2",
          "data-[state=inactive]:opacity-50",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  asChild = false,
  ...props
}: React.ComponentProps<"button"> & {
  asChild?: boolean
}) {
  const { onStepClick } = useStepper()
  const { step } = useStepItem()

  return (
    <button
      data-slot="stepper-trigger"
      type="button"
      className={cn(
        "inline-flex items-center gap-3 rounded-md outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        onStepClick && "cursor-pointer",
        className
      )}
      onClick={() => onStepClick?.(step)}
      {...props}
    >
      {children}
    </button>
  )
}

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepItem()

  return (
    <div
      data-slot="stepper-indicator"
      data-state={state}
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" &&
          "border-primary bg-primary text-primary-foreground",
        state === "inactive" && "border-muted-foreground text-muted-foreground",
        className
      )}
      {...props}
    >
      {state === "completed" ? (
        <svg
          xmlns="http://www.w3.org/2000/svg"
          width="16"
          height="16"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
          className="size-4"
        >
          <polyline points="20 6 9 17 4 12" />
        </svg>
      ) : (
        children
      )}
    </div>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepItem()

  return (
    <div
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium",
        state === "active" && "text-foreground",
        state === "completed" && "text-foreground",
        state === "inactive" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

